import React from 'react';
import { BrowserRouter, Routes, Route, Link } from 'react-router-dom';
import Home from './pages/Home';
import Clientes from './pages/Clientes';
import Categorias from './pages/Categorias';
import NovaOS from './pages/NovaOS';
import Relatorios from './pages/Relatorios';

function App() {
    return (
        <BrowserRouter>
            <div style={{ padding: '20px' }}>
                <nav style={{ marginBottom: '20px', display: 'flex', gap: '15px', borderBottom: '1px solid #ccc', paddingBottom: '10px', flexWrap: 'wrap' }}>
                    <Link to="/" style={{ textDecoration: 'none', color: '#007bff' }}>🏠 Home</Link>
                    <Link to="/clientes" style={{ textDecoration: 'none', color: '#007bff' }}>👥 Clientes</Link>
                    <Link to="/categorias" style={{ textDecoration: 'none', color: '#007bff' }}>📂 Categorias</Link>
                    <Link to="/nova-os" style={{ textDecoration: 'none', color: '#007bff' }}>➕ Nova OS</Link>
                    <Link to="/relatorios" style={{ textDecoration: 'none', color: '#007bff' }}>📊 Relatórios</Link>
                </nav>
                <Routes>
                    <Route path="/" element={<Home />} />
                    <Route path="/clientes" element={<Clientes />} />
                    <Route path="/categorias" element={<Categorias />} />
                    <Route path="/nova-os" element={<NovaOS />} />
                    <Route path="/relatorios" element={<Relatorios />} />
                </Routes>
            </div>
        </BrowserRouter>
    );
}

export default App;
